const STORAGE_KEY = "notepad-content";

let _beforeUnloadHandler = null;

export function loadContent() {
    return localStorage.getItem(STORAGE_KEY) || "";
}

export function saveContent(content) {
    localStorage.setItem(STORAGE_KEY, content);
}

export function clearContent() {
    localStorage.removeItem(STORAGE_KEY);
}

export function enableBeforeUnload() {
    if (_beforeUnloadHandler) return;
    _beforeUnloadHandler = (e) => {
        e.preventDefault();
    };
    window.addEventListener("beforeunload", _beforeUnloadHandler);
}

export function disableBeforeUnload() {
    if (!_beforeUnloadHandler) return;
    window.removeEventListener("beforeunload", _beforeUnloadHandler);
    _beforeUnloadHandler = null;
}

@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<script type="module" src="@Assets["Components/Pages/Notepad.razor.js"]"></script>

<h1>Notepad</h1>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="content" @bind:event="oninput"></textarea>
</div>

<div class="d-flex align-items-center gap-3">
    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = "";
    private string savedContent = "";
    private DateTime? lastSavedAt;
    private IJSObjectReference? module;
    private Timer? autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        module = await JS.InvokeAsync<IJSObjectReference>("import",
            Assets["Components/Pages/Notepad.razor.js"]);

        content = await module.InvokeAsync<string>("loadContent");
        savedContent = content;

        autoSaveTimer = new Timer(async _ =>
        {
            await InvokeAsync(async () =>
            {
                if (content != savedContent)
                {
                    await SaveAsync();
                    StateHasChanged();
                }
            });
        }, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));

        StateHasChanged();
    }

    private bool HasUnsavedChanges => content != savedContent;

    protected override async Task OnAfterRenderAsync()
    {
        if (module is null) return;

        if (HasUnsavedChanges)
            await module.InvokeVoidAsync("enableBeforeUnload");
        else
            await module.InvokeVoidAsync("disableBeforeUnload");
    }

    private async Task SaveAsync()
    {
        if (module is null) return;
        await module.InvokeVoidAsync("saveContent", content);
        savedContent = content;
        lastSavedAt = DateTime.Now;
    }

    private async Task SaveNowAsync()
    {
        await SaveAsync();
    }

    private async Task ClearAsync()
    {
        if (module is null) return;
        content = "";
        savedContent = "";
        lastSavedAt = null;
        await module.InvokeVoidAsync("clearContent");
        await module.InvokeVoidAsync("disableBeforeUnload");
    }

    public async ValueTask DisposeAsync()
    {
        autoSaveTimer?.Dispose();

        if (module is not null)
        {
            try
            {
                await module.InvokeVoidAsync("disableBeforeUnload");
                await module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
    }
}

